namespace sv_e5ab44cab4704e518337bbb7174fa402.Services;

public enum ThemeMode
{
    Light,
    Dark,
    System
}

/// <summary>
/// Scoped service — one instance per circuit, so each user gets independent state.
/// Persists across enhanced navigations within the same circuit.
/// </summary>
public class ThemeService
{
    private ThemeMode _theme = ThemeMode.System;
    private string _accentColor = "#0d6efd";

    public ThemeMode Theme
    {
        get => _theme;
        set
        {
            if (_theme == value) return;
            _theme = value;
            NotifyChanged();
        }
    }

    public string AccentColor
    {
        get => _accentColor;
        set
        {
            if (_accentColor == value) return;
            _accentColor = value;
            NotifyChanged();
        }
    }

    public event Action? OnChanged;

    private void NotifyChanged() => OnChanged?.Invoke();
}

@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<span class="theme-indicator" style="color: @ThemeService.AccentColor;" title="Current theme">
    @GetThemeIcon() @ThemeService.Theme
</span>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChanged += HandleThemeChanged;
    }

    private void HandleThemeChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    private string GetThemeIcon() => ThemeService.Theme switch
    {
        ThemeMode.Light => "☀️",
        ThemeMode.Dark => "🌙",
        ThemeMode.System => "💻",
        _ => "💻"
    };

    public void Dispose()
    {
        ThemeService.OnChanged -= HandleThemeChanged;
    }
}

@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<button class="btn btn-sm btn-outline-secondary" @onclick="CycleTheme"
        title="Toggle theme">
    @GetThemeIcon()
</button>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChanged += HandleThemeChanged;
    }

    private void CycleTheme()
    {
        ThemeService.Theme = ThemeService.Theme switch
        {
            ThemeMode.Light => ThemeMode.Dark,
            ThemeMode.Dark => ThemeMode.System,
            ThemeMode.System => ThemeMode.Light,
            _ => ThemeMode.Light
        };
    }

    private string GetThemeIcon() => ThemeService.Theme switch
    {
        ThemeMode.Light => "☀️",
        ThemeMode.Dark => "🌙",
        ThemeMode.System => "💻",
        _ => "💻"
    };

    private void HandleThemeChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        ThemeService.OnChanged -= HandleThemeChanged;
    }
}

@page "/settings"
@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card mt-4" style="max-width: 500px;">
    <div class="card-body">
        <h5 class="card-title">Theme</h5>

        <div class="btn-group mb-3" role="group">
            @foreach (var mode in Enum.GetValues<ThemeMode>())
            {
                <button class="btn @(ThemeService.Theme == mode ? "btn-primary" : "btn-outline-primary")"
                        @onclick="() => ThemeService.Theme = mode">
                    @mode
                </button>
            }
        </div>

        <h5 class="card-title">Accent Color</h5>

        <div class="d-flex align-items-center gap-3 mb-3">
            <input type="color" class="form-control form-control-color"
                   value="@ThemeService.AccentColor"
                   @onchange="OnAccentColorChanged" />
            <span style="color: @ThemeService.AccentColor; font-weight: bold;">
                @ThemeService.AccentColor
            </span>
        </div>

        <p class="text-muted small">
            Changes apply instantly across the entire app — check the
            header indicator and sidebar toggle.
        </p>
    </div>
</div>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChanged += HandleThemeChanged;
    }

    private void OnAccentColorChanged(ChangeEventArgs e)
    {
        ThemeService.AccentColor = e.Value?.ToString() ?? "#0d6efd";
    }

    private void HandleThemeChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        ThemeService.OnChanged -= HandleThemeChanged;
    }
}

