namespace sv_e5ab44cab4704e518337bbb7174fa402.Services;

public enum ThemeMode
{
    Light,
    Dark,
    System
}

/// <summary>
/// Scoped service — one instance per circuit, so each user gets independent state.
/// Persists across enhanced navigations within the same circuit.
/// </summary>
public class ThemeService
{
    private ThemeMode _theme = ThemeMode.System;
    private string _accentColor = "#0d6efd";

    public ThemeMode Theme
    {
        get => _theme;
        set
        {
            if (_theme == value) return;
            _theme = value;
            NotifyChanged();
        }
    }

    public string AccentColor
    {
        get => _accentColor;
        set
        {
            if (_accentColor == value) return;
            _accentColor = value;
            NotifyChanged();
        }
    }

    public event Action? OnChanged;

    private void NotifyChanged() => OnChanged?.Invoke();
}

